create table dirkspzm32.pps_unique_auftr_daten (
    unique_hash          varchar2(200 char) not null enable,
    unique_data          varchar2(4000 char) not null enable,
    last_fa_nr           number(*, 5) not null enable,
    erz_datum            date not null enable,
    erz_login_id         number(*, 0),
    aend_datum           date,
    aend_login_id        number(*, 0),
    soll_betriebsart     varchar2(10 char),
    prod_params          varchar2(4000 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0),
    sid                  varchar2(2 char) default '01' not null enable,
    firma_nr             number(6, 0) default 1 not null enable
);

alter table dirkspzm32.pps_unique_auftr_daten
    add constraint pk_pps_unique_auftr_daten primary key ( unique_hash )
        using index enable;


